from __future__ import annotations

import json
import re
import sys
from pathlib import Path

sys.stdout.reconfigure(encoding="utf-8")
REPO = Path("G:/Github/installed-persona-study")
sys.path.insert(0, str(REPO))

from harness.persona_core import normalize_text            # noqa: E402
from harness.polos_sujeito import ItemEscolha, pontua_sujeito, SUJEITOS_DEGENERADOS  # noqa: E402

BANCO = Path(__file__).with_name("v1_nao_generico.jsonl")
ITENS = [ItemEscolha(**json.loads(l)) for l in BANCO.read_text(encoding="utf-8").splitlines() if l.strip()]

PAL = re.compile(r"[\wà-üÀ-Ü]+", re.UNICODE)
VOG = set("aeiouáéíóúâêôãõàü")


def pals(s):
    return PAL.findall(normalize_text(s))


def pals_ac(s):
    return PAL.findall(s.lower())


# ---------------------------------------------------------------- features
def f_vogal_cons(s):
    ls = [c for c in s.lower() if c.isalpha()]
    v = sum(1 for c in ls if c in VOG)
    return v / max(1, len(ls) - v)


def f_silabas(s):
    """Contagem aproximada de silabas: grupos vocalicos."""
    n, prev = 0, False
    for c in s.lower():
        cur = c in VOG
        if cur and not prev:
            n += 1
        prev = cur
    return n


def f_pos_virgula(s):
    i = s.find(",")
    return (i / max(1, len(s))) if i >= 0 else 1.0


def f_dois_pontos(s):
    return s.count(":")


def f_clausulas(s):
    return 1 + sum(s.count(c) for c in ",;:")


def f_eu(s):
    p = pals(s)
    return sum(1 for w in p if w in ("eu", "mim", "me", "comigo"))


def f_poss(s):
    p = pals(s)
    return sum(1 for w in p if w in ("meu", "minha", "meus", "minhas"))


def f_1p(s):
    return f_eu(s) + f_poss(s)


def f_deitico(s):
    p = pals(s)
    return sum(1 for w in p if w in ("aqui", "agora", "hoje", "isto", "este", "esta", "ja"))


def f_modal(s):
    p = pals(s)
    return sum(1 for w in p if w in ("posso", "devo", "consigo", "quero", "preciso", "sei",
                                     "poderia", "deveria"))


def f_reaproveita(ctx, s):
    c, o = set(pals(ctx)), pals(s)
    return sum(1 for w in o if w in c)


def bigrams(s):
    p = pals(s)
    return set(zip(p, p[1:]))


def f_bigrama_ctx(ctx, s):
    return len(bigrams(ctx) & bigrams(s))


def f_ult_subst_ctx(ctx, s):
    """Repete a ultima palavra de conteudo do contexto?"""
    p = [w for w in pals(ctx) if len(w) > 3]
    return 1 if p and p[-1] in pals(s) else 0


def f_verbo_inicial(s):
    w = pals(s)[0] if pals(s) else ""
    return 1 if w.endswith(("o", "ei", "i", "a", "e")) and w not in (
        "a", "e", "o", "que", "uma", "um", "ele", "ela", "isso", "aqui") else 0


def f_termina_subst(s):
    p = pals(s)
    return 0 if not p else (1 if p[-1] not in ("tudo", "ele", "ela", "mim", "meu", "isso") and
                            not p[-1].endswith(("ei", "i", "ou", "o", "u")) else 0)


def f_totalizante(s):
    n = normalize_text(s)
    return sum(n.count(t) for t in ("tudo", " nada", "sempre", "so ele", "so isso", "o padrao"))


def f_generico(s):
    n = normalize_text(s)
    return sum(n.count(t) for t in ("de serie", "de fabrica", "comum", "padrao", "fabrica",
                                    "crua", "a base"))


def f_dens(s):
    p = pals(s)
    return sum(len(w) for w in p) / max(1, len(p))


def f_npal(s):
    return len(pals(s))


def f_maiuscula(s):
    return sum(1 for c in s if c.isupper())


def f_acentos(s):
    return sum(1 for c in s if c in "áéíóúâêôãõàçü")


def f_edit(a, b):
    """Distancia de edicao por palavra (prefixo/sufixo comum descontado)."""
    pa, pb = pals(a), pals(b)
    i = 0
    while i < min(len(pa), len(pb)) and pa[i] == pb[i]:
        i += 1
    return i  # tamanho do prefixo comum


def f_perg(s):
    return s.count("?")


def f_futuro(s):
    n = normalize_text(s)
    return sum(1 for w in pals(s) if w.endswith(("ra", "rao", "ria", "riam", "vera")))


def f_passado1p(s):
    return sum(1 for w in pals(s) if w.endswith(("ei", "i")) and len(w) > 3)


# ---------------------------------------------------------------- candidatas
def mk_simples(nome, feat, maior=True, doc=""):
    def h(ctx, a, b, _f=feat, _m=maior):
        va, vb = _f(a), _f(b)
        if va == vb:
            return "1"
        return "1" if ((va > vb) == _m) else "2"
    h.__name__ = nome
    h.__doc__ = doc
    return nome, h


def mk_ctx(nome, feat, maior=True, doc=""):
    def h(ctx, a, b, _f=feat, _m=maior):
        va, vb = _f(ctx, a), _f(ctx, b)
        if va == vb:
            return "1"
        return "1" if ((va > vb) == _m) else "2"
    h.__name__ = nome
    h.__doc__ = doc
    return nome, h


CANDS = []
for nome, feat in [("vogal_cons", f_vogal_cons), ("silabas", f_silabas),
                   ("pos_virgula", f_pos_virgula), ("dois_pontos", f_dois_pontos),
                   ("clausulas", f_clausulas), ("pron_eu", f_eu), ("possessivo", f_poss),
                   ("primeira_pessoa", f_1p), ("deitico", f_deitico), ("modal", f_modal),
                   ("verbo_inicial", f_verbo_inicial), ("termina_subst", f_termina_subst),
                   ("totalizante", f_totalizante), ("generico_lex", f_generico),
                   ("densidade", f_dens), ("n_palavras", f_npal), ("maiuscula", f_maiuscula),
                   ("acentos", f_acentos), ("pergunta", f_perg), ("futuro", f_futuro),
                   ("passado_1p", f_passado1p)]:
    CANDS.append(mk_simples(nome + "_MAIS", feat, True))
    CANDS.append(mk_simples(nome + "_MENOS", feat, False))

for nome, feat in [("reaproveita_ctx", f_reaproveita), ("bigrama_ctx", f_bigrama_ctx),
                   ("ult_subst_ctx", f_ult_subst_ctx)]:
    CANDS.append(mk_ctx(nome + "_MAIS", feat, True))
    CANDS.append(mk_ctx(nome + "_MENOS", feat, False))


# ---- compostas explicitas -------------------------------------------------
def comp_1p_dens(ctx, a, b):
    """1a pessoa explicita; desempata por densidade lexica."""
    va, vb = f_1p(a), f_1p(b)
    if va != vb:
        return "1" if va > vb else "2"
    return "1" if f_dens(a) > f_dens(b) else "2"


CANDS.append(("comp_1p_densidade", comp_1p_dens))


def comp_fuga_generico(ctx, a, b):
    """Foge do lexico de serie/fabrica; desempata por 1a pessoa."""
    va, vb = f_generico(a), f_generico(b)
    if va != vb:
        return "1" if va < vb else "2"
    ea, eb = f_1p(a), f_1p(b)
    if ea != eb:
        return "1" if ea > eb else "2"
    return "1"


CANDS.append(("comp_fuga_generico", comp_fuga_generico))


def comp_totaliza(ctx, a, b):
    """Foge do fecho totalizante; desempata por 1a pessoa."""
    va, vb = f_totalizante(a) + f_generico(a), f_totalizante(b) + f_generico(b)
    if va != vb:
        return "1" if va < vb else "2"
    ea, eb = f_1p(a), f_1p(b)
    if ea != eb:
        return "1" if ea > eb else "2"
    return "1"


CANDS.append(("comp_totaliza_fuga", comp_totaliza))


def comp_clausula_dens(ctx, a, b):
    ca, cb = f_clausulas(a), f_clausulas(b)
    if ca != cb:
        return "1" if ca < cb else "2"
    return "1" if f_dens(a) > f_dens(b) else "2"


CANDS.append(("comp_clausula_densidade", comp_clausula_dens))


def comp_bigrama_1p(ctx, a, b):
    ba, bb = f_bigrama_ctx(ctx, a), f_bigrama_ctx(ctx, b)
    if ba != bb:
        return "1" if ba < bb else "2"
    ea, eb = f_1p(a), f_1p(b)
    if ea != eb:
        return "1" if ea > eb else "2"
    return "1"


CANDS.append(("comp_bigrama_1p", comp_bigrama_1p))


def comp_ultima_pal(ctx, a, b):
    """Le so' a ULTIMA palavra de conteudo: verbo (termina em vogal atona de 1a/3a) vence."""
    fim = lambda s: pals(s)[-1] if pals(s) else ""  # noqa: E731
    va, vb = len(fim(a)), len(fim(b))
    if va != vb:
        return "1" if va > vb else "2"
    return "1"


CANDS.append(("comp_ultima_palavra_longa", comp_ultima_pal))


# ---------------------------------------------------------------- execucao
def main():
    print(f"BANCO {BANCO.name} — {len(ITENS)} itens (estrato nao_generico)\n")
    print("=== PISO: os 16 que ja existem ===")
    base = []
    for nome, s in sorted(SUJEITOS_DEGENERADOS.items()):
        t = pontua_sujeito(s, ITENS)["taxa"]
        base.append((t, nome))
    for t, nome in sorted(base, reverse=True):
        print(f"  {nome:<22} {t:.3f}")
    print(f"\n  PISO = {max(base)[0]:.3f} ({max(base)[1]})\n")

    print(f"=== NOVAS: {len(CANDS)} candidatas executadas ===")
    res = []
    for nome, h in CANDS:
        t = pontua_sujeito(h, ITENS)["taxa"]
        res.append((t, nome, h))
    for t, nome, _ in sorted(res, key=lambda r: -r[0]):
        marca = "  <== RESOLVE" if t >= 0.90 else ("  <- PARCIAL" if t >= 0.75 else "")
        print(f"  {nome:<32} {t:.3f}{marca}")
    print(f"\nEXECUTADAS: {len(CANDS)}")
    melhor = max(res, key=lambda r: r[0])
    print(f"MELHOR NOVA: {melhor[1]} = {melhor[0]:.3f}")
    return res


if __name__ == "__main__":
    main()
