    return vencedor(a.count(";") - a.count(":"), b.count(";") - b.count(":")) or "1"


@reg
def virgula(ctx, a, b):
    return vencedor(a.count(","), b.count(","), maior=False) or "1"


@reg
def interrogacao(ctx, a, b):
