@reg
def razao_vogal(ctx, a, b):
    r = lambda s: sum(c in "aeiouáéíóúâêôãõà" for c in norm(s).replace("~", "")) / max(1, len(PAL.findall(s)))  # noqa: E731
    razao = lambda s: sum(c in "aeiou" for c in norm(s)) / max(1, sum(c.isalpha() for c in norm(s)))  # noqa: E731
    return vencedor(razao(a), razao(b)) or "1"


@reg
def razao_vogal_baixa(ctx, a, b):
    razao = lambda s: sum(c in "aeiou" for c in norm(s)) / max(1, sum(c.isalpha() for c in norm(s)))  # noqa: E731
    return vencedor(razao(a), razao(b), maior=False) or "1"


@reg
def silabas(ctx, a, b):
    """Numero de nucleos vocalicos (aproximacao de silabas)."""
    sil = lambda s: len(re.findall(r"[aeiou]+", norm(s)))  # noqa: E731
    return vencedor(sil(a), sil(b)) or "1"


@reg
def n_palavras(ctx, a, b):
