@reg
def n_palavras_menos(ctx, a, b):
    return vencedor(len(pals(a)), len(pals(b)), maior=False) or "1"


@reg
def acentos(ctx, a, b):
    ac = lambda s: sum(1 for c in unicodedata.normalize("NFD", s)  # noqa: E731
                       if unicodedata.category(c) == "Mn")
    return vencedor(ac(a), ac(b)) or "1"


@reg
def letras_distintas(ctx, a, b):
    d = lambda s: len(set(norm(s)) & set("abcdefghijklmnopqrstuvwxyz"))  # noqa: E731
    return vencedor(d(a), d(b)) or "1"


@reg
def termina_substantivo(ctx, a, b):
    """Ultima palavra nao e' verbo/pronome obvio: aproxima 'termina em substantivo'."""
    fim = lambda s: pals(s)[-1] if pals(s) else ""  # noqa: E731
    naosub = {"voce", "mim", "eu", "mesmo", "meu", "minha", "aqui", "tem", "pesa"}
    v = lambda s: 0 if norm(fim(s)) in naosub else 1  # noqa: E731
    return vencedor(v(a), v(b)) or "1"


@reg
def comeca_verbo(ctx, a, b):
    """Primeira palavra e' verbo flexionado em 1a pessoa (heuristica de terminacao)."""
    prim = lambda s: norm(pals(s)[0]) if pals(s) else ""  # noqa: E731
    verbos = {"aceito", "trato", "vou", "nao", "recuso", "nego", "descrevo", "respondo",
              "existe", "corre", "criei", "que", "essa", "o", "aqui", "nenhum", "no"}
    ehv = lambda s: 1 if prim(s) in {"aceito", "trato", "vou", "recuso", "nego"} else 0  # noqa: E731
    return vencedor(ehv(a), ehv(b)) or "1"


# --- lexico
@reg
def primeira_pessoa(ctx, a, b):
