    return vencedor(c(a), c(b), maior=False) or "1"


@reg
def possessivo(ctx, a, b):
    poss = {"meu", "minha", "meus", "minhas"}
    c = lambda s: sum(1 for w in pals(s) if norm(w) in poss)  # noqa: E731
    return vencedor(c(a), c(b), maior=False) or "1"


@reg
def deitico(ctx, a, b):
    d = {"aqui", "agora", "hoje", "esse", "essa", "isso", "este", "esta"}
    c = lambda s: sum(1 for w in pals(s) if norm(w) in d)  # noqa: E731
    return vencedor(c(a), c(b), maior=False) or "1"


@reg
def modal(ctx, a, b):
    m = {"posso", "devo", "consigo", "vou", "preciso", "quero", "sei"}
    c = lambda s: sum(1 for w in pals(s) if norm(w) in m)  # noqa: E731
