@reg
def subjuntivo(ctx, a, b):
    """Verbo em subjuntivo/futuro do preterito: terminacoes -sse, -ria, -que, -ça, -sse."""
    pad = re.compile(r"\b\w+(?:sse|ssem|ria|riam|asse|esse|isse)\b|\b(?:faca|machuque|seja|"
                     r"tenha|possa|fosse)\b")
    c = lambda s: len(pad.findall(norm(s)))  # noqa: E731
    return vencedor(c(a), c(b)) or "1"


@reg
def irrealis(ctx, a, b):
    """Modo irrealis: subjuntivo, condicional ou interrogativa."""
    pad = re.compile(r"\w+(?:sse|ssem|ria|riam)\b|\b(?:faca|machuque|seja|tenha|possa|"
                     r"suposto|sustente)\b")
    c = lambda s: len(pad.findall(norm(s))) + s.count("?")  # noqa: E731
    return vencedor(c(a), c(b)) or "1"


@reg
def sufixo_abstrato(ctx, a, b):
    pad = re.compile(r"\w+(?:cao|coes|mento|mentos|ismo|dade|encia|ancia)\b")
    c = lambda s: len(pad.findall(norm(s)))  # noqa: E731
    return vencedor(c(a), c(b)) or "1"


@reg
