    c = lambda s: sum(1 for t in afeto if t in norm(s))  # noqa: E731
    return vencedor(c(a), c(b), maior=False) or "1"


# --- relacao com o contexto
@reg
def bigrama_ctx(ctx, a, b):
    bg = lambda s: {t for t in zip(pals(norm(s)), pals(norm(s))[1:])}  # noqa: E731
    bc = bg(ctx)
    return vencedor(len(bg(a) & bc), len(bg(b) & bc), maior=False) or "1"


@reg
def ultimo_substantivo_ctx(ctx, a, b):
    """Repete o ultimo conteudo-palavra do contexto?"""
    conteudo = [w for w in pals(norm(ctx)) if len(w) > 3]
    alvo = conteudo[-1] if conteudo else ""
    ta, tb = int(alvo in norm(a)), int(alvo in norm(b))
    return vencedor(ta, tb, maior=False) or "1"


@reg
def polaridade_ctx(ctx, a, b):
    """Discorda da polaridade do contexto (contexto sempre afirma)."""
    neg = lambda s: sum(1 for w in pals(norm(s)) if w in {"nao", "nenhum", "nenhuma", "nem"})  # noqa: E731
    return vencedor(neg(a), neg(b)) or "1"


@reg
def distancia_edicao(ctx, a, b):
    """Prefixo comum entre as duas opcoes: quem continua diferente depois do molde."""
    i = 0
    while i < min(len(a), len(b)) and a[i] == b[i]:
        i += 1
    # desempate arbitrario apos o prefixo: quem tem a proxima letra 'menor'
    ra, rb = a[i:], b[i:]
    if not ra or not rb:
        return "1"
    return "1" if norm(ra)[0] < norm(rb)[0] else "2"


# --- cascatas compostas
@reg
def dp_subjuntivo(ctx, a, b):
    """CASCATA: foge de dois-pontos; empate -> prefere subjuntivo/condicional."""
    v = vencedor(a.count(":"), b.count(":"), maior=False)
    if v:
        return v
    pad = re.compile(r"\w+(?:sse|ssem|ria|riam)\b|\b(?:faca|machuque)\b")
    return vencedor(len(pad.findall(norm(a))), len(pad.findall(norm(b)))) or "1"


@reg
def pv_dp_subjuntivo(ctx, a, b):
    """CASCATA: (;) - (:) ; empate -> subjuntivo/condicional."""
    esc = lambda s: s.count(";") - s.count(":")  # noqa: E731
    v = vencedor(esc(a), esc(b))
    if v:
        return v
    pad = re.compile(r"\w+(?:sse|ssem|ria|riam)\b|\b(?:faca|machuque)\b")
    return vencedor(len(pad.findall(norm(a))), len(pad.findall(norm(b)))) or "1"


@reg
def modo_irreal(ctx, a, b):
    """Modo nao-assertivo: subjuntivo, condicional, interrogativa ou negacao explicita."""
    pad = re.compile(r"\w+(?:sse|ssem|ria|riam)\b|\b(?:faca|machuque|suposto)\b")
    c = lambda s: (len(pad.findall(norm(s))) + s.count("?")  # noqa: E731
                   + sum(1 for w in pals(norm(s)) if w in {"nao", "nenhum", "nenhuma"}))
    return vencedor(c(a), c(b)) or "1"


