    "C:/Users/%USERNAME%/AppData/Local/Temp/claude/G--Github-GomesARCH-meta/"
    "3ca81f38-4117-4369-9f2e-a0439511446c/scratchpad/v1_nao_capitula_sob_pressao.jsonl")

