PAL = re.compile(r"[\wà-üÀ-Ü]+", re.UNICODE)
VOG = set("aeiouáéíóúâêôãõàü")


def sem_acento(s: str) -> str:
    return "".join(c for c in unicodedata.normalize("NFD", s.lower())
                   if unicodedata.category(c) != "Mn")


def pals(s: str) -> list[str]:
    return PAL.findall(s.lower())


# ----------------------------------------------------------------- FEATURES
# Cada feature e' g(ctx, s) -> numero. A regra escolhe a opcao com MAIOR valor.

def f_terminais(ctx, s):        # numero de marcas terminais de sentenca . ? !
    return sum(s.count(c) for c in ".?!")


def f_virgulas(ctx, s):
    return -s.count(",")


def f_doispontos(ctx, s):
    return s.count(":")


def f_pontovirgula(ctx, s):
    return s.count(";")


def f_interrog(ctx, s):
    return s.count("?")


def f_fortes(ctx, s):           # toda pontuacao de fronteira forte
    return sum(s.count(c) for c in ":;?!") + max(0, s.count(".") - 1)


def f_pos_virgula(ctx, s):      # posicao relativa da 1a virgula (1.0 se nao ha)
    i = s.find(",")
    return 1.0 if i < 0 else i / max(1, len(s))


def f_vc(ctx, s):               # razao vogal/consoante
    letras = [c for c in sem_acento(s) if c.isalpha()]
    v = sum(1 for c in letras if c in "aeiou")
    return v / max(1, len(letras) - v)


def f_silabas(ctx, s):          # grupos vocalicos = proxy de silaba
    n, dentro = 0, False
    for c in s.lower():
        if c in VOG:
            if not dentro:
                n += 1
            dentro = True
        else:
            dentro = False
    return n


def f_npals(ctx, s):
    return len(pals(s))


def f_dens(ctx, s):             # tamanho medio de palavra
    p = pals(s)
    return sum(len(x) for x in p) / max(1, len(p))


def f_clausulas(ctx, s):        # cláusulas ~ fronteiras , ; : . ? ! + " e " + " que "
    n = sum(s.count(c) for c in ",;:")
    n += sum(s.count(c) for c in ".?!")
    return n


def f_eu(ctx, s):               # pronome de 1a pessoa explicito
    return int("eu" in pals(s))


def f_possessivo1(ctx, s):
    return sum(1 for w in pals(s) if w in {"meu", "minha", "meus", "minhas"})


def f_2pessoa(ctx, s):          # tu / te / teu / tua / -ste
    ws = pals(s)
    n = sum(1 for w in ws if w in {"tu", "te", "ti", "teu", "tua", "teus", "tuas", "contigo"})
    n += sum(1 for w in ws if w.endswith("ste") and len(w) > 4)
    return n


def f_deitico(ctx, s):
    return sum(1 for w in pals(s) if w in {"aqui", "agora", "hoje", "ja", "já", "este", "esta", "isto"})


def f_modal(ctx, s):
    return sum(1 for w in pals(s) if sem_acento(w) in
               {"posso", "devo", "consigo", "preciso", "quero", "vou", "poderia", "deveria"})


def f_verbo1p(ctx, s):          # primeira palavra e' verbo de 1a pessoa do singular (-o)
    p = pals(s)
    if not p:
        return 0
    w = sem_acento(p[0])
    return int(w.endswith("o") and len(w) > 3 and w not in {"todo", "tudo", "isso", "outro"})


def f_comeca_det(ctx, s):
    return int(pals(s)[:1] and pals(s)[0] in {"o", "a", "os", "as", "um", "uma"})


def f_neg(ctx, s):
    return sum(1 for w in pals(s) if sem_acento(w) in {"nao", "nem", "nenhum", "nenhuma", "ninguem", "nada"})


def f_e_coord(ctx, s):          # ", e " coordenacao aditiva
    return -len(re.findall(r",\s*e\b", s.lower()))


def f_que(ctx, s):
    return sum(1 for w in pals(s) if w == "que")


def f_overlap_uni(ctx, s):
    return len(set(pals(ctx)) & set(pals(s)))


def _bigr(x):
    p = pals(x)
    return set(zip(p, p[1:]))


def f_overlap_bi(ctx, s):
    return len(_bigr(ctx) & _bigr(s))


def _stems(x, k=4):
    return {sem_acento(w)[:k] for w in pals(x) if len(w) >= k}


def f_eco_stem(ctx, s):         # reaproveitamento de radical do contexto
    return len(_stems(ctx) & _stems(s))


def f_eco_verbo_final(ctx, s):
    """Radical do ULTIMO verbo/palavra de conteudo do contexto reaparece na opcao."""
    p = [w for w in pals(ctx) if len(w) >= 5]
    if not p:
        return 0
    alvo = sem_acento(p[-1])[:4]
    return int(any(sem_acento(w).startswith(alvo) for w in pals(s)))


def f_eco_imperativo(ctx, s):
    """O contexto traz uma ordem; a opcao repete o radical de ALGUMA palavra >=5 do ctx
    na PRIMEIRA palavra dela (obedecer com o verbo do outro)."""
    p = pals(s)
    if not p:
        return 0
    r = sem_acento(p[0])[:3]
    return int(len(r) == 3 and any(sem_acento(w).startswith(r) for w in pals(ctx) if len(w) >= 4))


def f_termina_subst(ctx, s):
    """Ultima palavra nao e' verbo flexionado obvio (proxy: nao termina em o/e/i/u de verbo)."""
    p = pals(s)
    if not p:
        return 0
    w = sem_acento(p[-1])
    return int(w.endswith(("a", "as", "o", "os", "em", "ao", "or", "ade", "ura", "ao")) and len(w) > 3)


def f_primeira_maiuscula_verbo(ctx, s):
    return f_verbo1p(ctx, s)


def f_len(ctx, s):
    return len(s)


def f_numero(ctx, s):           # nomeia numero/quantidade concreta
    return sum(1 for w in pals(s) if sem_acento(w) in
               {"vinte", "tres", "sete", "numero", "conta", "contagem", "linha", "prazo"})


FEATURES = {
    "terminais": f_terminais, "virgulas": f_virgulas, "doispontos": f_doispontos,
    "pontovirgula": f_pontovirgula, "interrog": f_interrog, "fortes": f_fortes,
