def faz_regra(chaves_sinais):
    """Cascata lexicografica. chaves_sinais = [(nome, +1|-1), ...]. Escolhe MAIOR."""
    def regra(ctx, a, b):
        for nome, sinal in chaves_sinais:
            g = FEATURES[nome]
            va, vb = sinal * g(ctx, a), sinal * g(ctx, b)
            if va != vb:
                return "1" if va > vb else "2"
        return "1"
    return regra


def taxa(chaves_sinais):
    return pontua_sujeito(faz_regra(chaves_sinais), ITENS)["taxa"]


